SELECT * FROM (SELECT TRY_CAST("YEAR" AS INTEGER) AS year, TRY_CAST("MONTH_NUM" AS INTEGER) AS month, make_date(TRY_CAST("YEAR" AS INTEGER), TRY_CAST("MONTH_NUM" AS INTEGER), 1) AS date, NULLIF("APT_ICAO", '') AS apt_icao, NULLIF("APT_NAME", '') AS apt_name, NULLIF("STATE_NAME", '') AS state_name, NULLIF("MONTH_MON", '') AS month_mon, NULLIF("COMMENT", '') AS comment, TRY_CAST("TF" AS DOUBLE) AS tf, TRY_CAST("VALID_FL" AS DOUBLE) AS valid_fl, TRY_CAST("NO_REF" AS DOUBLE) AS no_ref, TRY_CAST("TOTAL_REF_NB_FL" AS DOUBLE) AS total_ref_nb_fl, TRY_CAST("TOTAL_REF_TIME_MIN" AS DOUBLE) AS total_ref_time_min, TRY_CAST("TOTAL_ADD_TIME_MIN" AS DOUBLE) AS total_add_time_min FROM "eurocontrol-asma-additional-time") WHERE date IS NOT NULL
